import React from 'react';

function DottedSphere({ size = 700, className = '' }) {
  return (
    <div className={`absolute pointer-events-none ${className}`} style={{
      width: size,
      height: size,
    }}>
      <style>{`
        @keyframes sphereRotate {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
        @keyframes spherePulse {
          0%, 100% { opacity: 0.6; transform: scale(1); }
          50% { opacity: 0.8; transform: scale(1.02); }
        }
        .dotted-sphere-container {
          animation: spherePulse 4s ease-in-out infinite;
        }
        .dotted-sphere-rotate {
          animation: sphereRotate 60s linear infinite;
        }
      `}</style>
      <div className="dotted-sphere-container" style={{ width: '100%', height: '100%' }}>
        <svg 
          className="dotted-sphere-rotate"
          width={size} 
          height={size} 
          viewBox={`0 0 ${size} ${size}`}
          style={{ overflow: 'visible' }}
        >
          <defs>
            <radialGradient id="sphereGradient" cx="30%" cy="30%" r="70%">
              <stop offset="0%" stopColor="#a855f7" stopOpacity="0.9" />
              <stop offset="40%" stopColor="#7c3aed" stopOpacity="0.6" />
              <stop offset="70%" stopColor="#3b82f6" stopOpacity="0.4" />
              <stop offset="100%" stopColor="#0ea5e9" stopOpacity="0.1" />
            </radialGradient>
            <radialGradient id="dotGlow" cx="50%" cy="50%" r="50%">
              <stop offset="0%" stopColor="#c084fc" stopOpacity="1" />
              <stop offset="100%" stopColor="#7c3aed" stopOpacity="0.3" />
            </radialGradient>
          </defs>

          {/* Sphere glow background */}
          <ellipse 
            cx={size/2} 
            cy={size/2} 
            rx={size/2.2} 
            ry={size/2.5}
            fill="url(#sphereGradient)"
            opacity="0.3"
          />

          {/* Dotted rings - 3D sphere effect */}
          {Array.from({ length: 28 }).map((_, ring) => {
            const ringProgress = ring / 28;
            const ringAngle = ringProgress * Math.PI;
            const ringRadius = Math.sin(ringAngle) * (size / 2.3);
            const ringY = Math.cos(ringAngle) * (size / 3) + size / 2;
            const numDots = Math.floor(Math.sin(ringAngle) * 50) + 8;
            const opacity = 0.3 + Math.sin(ringAngle) * 0.5;

            return Array.from({ length: numDots }).map((_, i) => {
              const dotAngle = (i / numDots) * Math.PI * 2;
              const x = Math.cos(dotAngle) * ringRadius + size / 2;
              const y = ringY + Math.sin(dotAngle) * ringRadius * 0.15;
              const dotSize = 1.2 + Math.sin(ringAngle) * 1.8;

              // Color based on position
              const hue = 260 + (ringProgress * 40);

              return (
                <circle
                  key={`${ring}-${i}`}
                  cx={x}
                  cy={y}
                  r={dotSize}
                  fill={`hsl(${hue}, 80%, 70%)`}
                  opacity={opacity * (0.5 + Math.sin(dotAngle) * 0.5)}
                />
              );
            });
          })}

          {/* Highlight ring */}
          <ellipse
            cx={size/2}
            cy={size/2}
            rx={size/2.5}
            ry={size/6}
            fill="none"
            stroke="url(#dotGlow)"
            strokeWidth="1"
            opacity="0.4"
          />
        </svg>
      </div>
    </div>
  );
}

export default DottedSphere;
